    let mut n: u64 = 0u64;
    // C: do { ... } while (isalnum((unsigned char)*s));
    loop {
        let byte = s[pos];
        let digit = if byte.is_ascii_digit() {
            (byte - b'0') as u32
        } else {
            // C: (toupper((unsigned char)*s) - 'A') + 10
            (byte.to_ascii_uppercase() - b'A') as u32 + 10
